props.code:
# Dict comprehension
words = ['hi', 'hello', 'hey']
lengths = {w: len(w) for w in words}
print(lengths)  # {'hi': 2, 'hello': 5, 'hey': 3}

# Set comprehension
nums = [1, 2, 2, 3, 3, 4]
unique_sq = {n**2 for n in nums}
print(unique_sq)  # {1, 4, 9, 16}

